<?php require_once __DIR__.'/config/auth.php'; require_login(); $user=current_user();$id=(int)($_GET['id']??0);$stmt=db()->prepare('SELECT file_path FROM cards WHERE id=? AND user_id=?');$stmt->bind_param('ii',$id,$user['id']);$stmt->execute();$card=$stmt->get_result()->fetch_assoc();if($card){if(!empty($card['file_path'])&&file_exists(__DIR__.'/'.$card['file_path']))@unlink(__DIR__.'/'.$card['file_path']);$del=db()->prepare('DELETE FROM cards WHERE id=? AND user_id=?');$del->bind_param('ii',$id,$user['id']);$del->execute();}header('Location: dashboard.php?ok='.urlencode('Item deleted.')); ?>